mapper.select:
select c1.id as commentId, c1.user_id as userId, u.username as username, u.user_avatar as userAvatar, c1.content as content, c1.create_time as createTime, u2.username as replyUsername, c1.has_children as hasChildren, c1.root_id as rootId, c1.parent_id as parentId
from tb_comment c1 join tb_user u ON c1.user_id = u.id left join tb_comment c2 ON c1.parent_id = c2.id left join tb_user u2 ON c2.user_id = u2.id WHERE c1.id in
#{item}
order by field(c1.id,
#{item}
)

select c1.id as commentId, c1.user_id as userId, u.username as username, u.user_avatar as userAvatar, c1.content as content, c1.create_time as createTime, u2.username as replyUsername, c1.root_id as rootId, c1.parent_id as parentId, c1.like_count as likeCount, c1.is_hot as isHot, (SELECT COUNT(*) FROM tb_comment WHERE root_id = c1.id) as childrenCount from tb_comment c1 join tb_user u ON c1.user_id = u.id LEFT JOIN tb_comment c2 ON c1.parent_id = c2.id left join tb_user u2 ON c2.user_id = u2.id
c1.playlist_id = #{playlistId}
c1.song_id = #{songId}
and c1.id < #{firstId}
and c1.root_id = #{rootId} and c1.is_hot = 0
order by c1.create_time
asc, c1.id asc
desc, c1.id desc
limit 200;

select c1.id as commentId, c1.user_id as userId, u.username as username, u.user_avatar as userAvatar, c1.content as content, c1.create_time as createTime, u2.username as replyUsername, c1.root_id as rootId, c1.parent_id as parentId, c1.like_count as likeCount, c1.is_hot as isHot, (SELECT COUNT(*) FROM tb_comment WHERE root_id = c1.id) as childrenCount from tb_comment c1 join tb_user u ON c1.user_id = u.id LEFT JOIN tb_comment c2 ON c1.parent_id = c2.id left join tb_user u2 ON c2.user_id = u2.id
c1.playlist_id = #{playlistId}
c1.song_id = #{songId}
and c1.root_id = 0 and c1.is_hot = 1
order by c1.like_count desc ,c1.id desc
